#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 4e5+5;
struct change{int opt,x,y;}cg[N];
int n,m,cnt,ans[N];
pii ln[N];
bool d[N],vis[N],hop[N];
vector<int> g[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS(int u,int tim){
    if(vis[u])return;vis[u]=1;
    //cout<<u<<","<<tim<<"!\n";
    ans[u]=max(ans[u],tim);
    for(int v:g[u])
        hop[v]|=hop[u],DFS(v,tim);return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)vis[i]=0,hop[i]=1;
    for(int i=1;i<=m;i++){
        char opt;cin>>opt;
        if(opt=='D'){
            int x=read();
            hop[x]=0;
            cg[i]={1,x,0};
        }else if(opt=='A'){
            int x=read(),y=read();
            ln[++cnt]={x,y},d[cnt]=1;
        }else{
            int id=read();
            d[id]=0;
            //cout<<i<<":"<<ln[id].fr<<" "<<ln[id].se<<"\n";
            cg[i]={2,ln[id].fr,ln[id].se};
        }
    }for(int i=1;i<=cnt;i++)if(d[i]){
        auto [x,y]=ln[i];
        g[x].pb(y),g[y].pb(x);
    }for(int i=1;i<=n;i++)if(hop[i])DFS(i,m);

    for(int i=m;i>=1;i--){
        auto [o,x,y]=cg[i];
        //cout<<i<<" : "<<o<<" , "<<x<<"->"<<y<<"\n";
        if(!o)continue;
        if(o==1)hop[x]=1,DFS(x,i-1);
        else{
            g[x].pb(y),g[y].pb(x);
            //cout<<"add "<<x<<" "<<y<<"\n";
            hop[x]|=hop[y],hop[y]|=hop[x];
            if(hop[x]||hop[y])DFS(x,i-1),DFS(y,i-1);
        }//cout<<"\n";
    }for(int i=1;i<=n;i++)cout<<ans[i]<<"\n";
    return 0;
}
